mapper.update:
update course
subject = #{subject}, name = #{name}, price = #{price}, target = #{target}, description = #{description}, create_time = #{createTime}, update_time = #{updateTime}
where id = #{id}

mapper.select:
select id, subject, name, price, target, description, create_time, update_time
from course


        and name like concat('%',#{name},'%')


        and subject = #{subject}


        and target = #{target}
